import java.util.*;   // For ArrayList, HashMap etc., you might need these imports if not using standard libraries only ie Spring Boot and other frameworks that come with JDK/Spring Framework such as @Autowired for dependency injection in Java classes or getters & setter methods to manage properties
import javax.servlet.*;  // For ServletException, Request, Response etc., these are necessary if you're not using standard libraries only and also need HttpServletRequest ,HttpServletResponse objects inside servlets (like @PostMapping for HTTP POST request) or filters/interceptors like preHandle in Spring MVC
import javax.servlet.http.*;  // For this, we can use RequestMapingHandlerAdapter to map URLs with handlers which is used when using JSP and Servlets etc., if not standard libraries only then you're required for these imports as well (like @RequestMapping in Spring MVC)
import org.springframework.security.*; // For Authentication, GrantedAuthority , UserDetails interfaces below are all autowired or setters/getter methods by default used when using Java-based security setup with a framework like spring Security OR JWT for JSON Web Tokens etc.,  if not standard libraries only then you'll need these imports.
import org.springframework.security.authentication.*; // If we are going to use PasswordEncoder, it is needed below as well (if using Spring’s password encoder)